ALGORITHM RotatePointAboutOrigin(x, y, theta)
// theta is in degrees
BEGIN
 // Convert angle to radians
 radian ← theta × (π / 180)

 // Calculate new coordinates using rotation formulas
 x_new ← x × cos(radian) - y × sin(radian)
 y_new ← x × sin(radian) + y × cos(radian)

 RETURN (x_new, y_new)
END
